manifest_content:
// ==============================================================================
// MasterDnsVPN
// Author: MasterkinG32
// Github: https://github.com/masterking32
// Year: 2026
// ==============================================================================

module masterdnsvpn-go

go 1.25.0

require (
	github.com/BurntSushi/toml v1.4.0
	github.com/klauspost/compress v1.18.5
	github.com/pierrec/lz4/v4 v4.1.26
	golang.org/x/crypto v0.49.0
	golang.org/x/sys v0.42.0
)

{
  "name": "@openai/codex-plugin-cc",
  "version": "1.0.5",
  "private": true,
  "type": "module",
  "description": "Use Codex from Claude Code to review code or delegate tasks.",
  "license": "Apache-2.0",
  "engines": {
    "node": ">=18.18.0"
  },
  "scripts": {
    "bump-version": "node scripts/bump-version.mjs",
    "check-version": "node scripts/bump-version.mjs --check",
    "prebuild": "mkdir -p plugins/codex/.generated/app-server-types && codex app-server generate-ts --out plugins/codex/.generated/app-server-types",
    "build": "tsc -p tsconfig.app-server.json",
    "test": "node --test tests/*.test.mjs"
  },
  "devDependencies": {
    "@types/node": "^25.5.0",
    "typescript": "^6.0.2"
  }
}

[workspace]
resolver = "2"
members = [
    "crates/agentos-protocol",
    "crates/agentos-sidecar-core",
    "crates/agentos-sidecar",
    # LOCAL-DEV (web/wasm convergence): re-added because the converged
    # `secure-exec-sidecar-browser` is provided via the local ../secure-exec-convwasi
    # link. Before a real push this must go back to excluded (or be pinned to a
    # published browser crate) — secure-exec does not publish it to crates.io yet.
    "crates/agentos-sidecar-browser",
    "crates/client",
    "crates/agentos-actor-plugin",
]

[workspace.package]
version = "0.2.0-rc.3"
edition = "2021"
license = "Apache-2.0"
repository = "https://github.com/rivet-dev/agent-os"

# AgentOS crates are published as a lock-step chain. Secure Exec is consumed as
# normal crates.io dependencies so CI/publish builds do not need a sibling
# checkout.
[workspace.dependencies]
agentos-bridge = { package = "secure-exec-bridge", path = "../secure-exec-convwasi/crates/bridge", version = "0.3.0-rc.1" }
agentos-protocol = { path = "crates/agentos-protocol", version = "0.2.0-rc.3" }
agentos-sidecar-core = { path = "crates/agentos-sidecar-core", version = "0.2.0-rc.3" }
agentos-sidecar = { path = "crates/agentos-sidecar", version = "0.2.0-rc.3" }
agentos-sidecar-browser = { path = "crates/agentos-sidecar-browser", version = "0.2.0-rc.3" }
agentos-kernel = { package = "secure-exec-kernel", path = "../secure-exec-convwasi/crates/kernel", version = "0.3.0-rc.1" }
agentos-execution = { package = "secure-exec-execution", path = "../secure-exec-convwasi/crates/execution", version = "0.3.0-rc.1" }
agentos-v8-runtime = { package = "secure-exec-v8-runtime", path = "../secure-exec-convwasi/crates/v8-runtime", version = "0.3.0-rc.1" }
secure-exec-client = { path = "../secure-exec-convwasi/crates/secure-exec-client", version = "0.3.0-rc.1" }
secure-exec-bridge = { path = "../secure-exec-convwasi/crates/bridge", version = "0.3.0-rc.1" }
secure-exec-sidecar = { path = "../secure-exec-convwasi/crates/sidecar", version = "0.3.0-rc.1" }
# LOCAL-DEV: unpublished converged browser crate from the convwasi link (web/wasm work).
secure-exec-sidecar-browser = { path = "../secure-exec-convwasi/crates/sidecar-browser", version = "0.3.0-rc.1" }
secure-exec-vm-config = { path = "../secure-exec-convwasi/crates/vm-config", version = "0.3.0-rc.1" }
vbare = "0.0.4"
vbare-compiler = { package = "rivet-vbare-compiler", version = "0.0.5" }
